def is_prime(number: int) -> bool:
    if not isinstance(number, int) or isinstance(number, bool):
        raise TypeError("number must be an int (bool not allowed)")
    if number < 2:
        return False
    if number < 4:
        return True
    if number % 2 == 0 or number % 3 == 0:
        return False
    i = 5
    while i * i <= number:
        if number % i == 0 or number % (i + 2) == 0:
            return False
        i += 6
    return True
